import{_ as e,c as o,o as t,ag as i}from"./chunks/framework.B-XtCDNB.js";const p=JSON.parse('{"title":"Valadoc Guide","description":"","frontmatter":{},"headers":[],"relativePath":"developer-guides/documentation/valadoc-guide.md","filePath":"developer-guides/documentation/valadoc-guide.md","lastUpdated":1776547011000}'),n={name:"developer-guides/documentation/valadoc-guide.md"};function l(r,a,d,c,m,s){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="valadoc-guide" tabindex="-1">Valadoc Guide <a class="header-anchor" href="#valadoc-guide" aria-label="Permalink to &quot;Valadoc Guide&quot;">​</a></h1><p><code>valadoc</code> is a command line tool that generates Vala programming documentation from a library&#39;s API (Application Programming Interface).</p><p>The library&#39;s API can be <a href="./../bindings/writing-a-vapi-manually.html">written manually</a> in a VAPI file or in a VAPI file or <a href="./../bindings/generating-a-vapi-with-gobject-introspection.html">generated automatically</a> from source files and held in a GIR (GObject Introspection Repository) file. valadoc can generate documentation from both a VAPI file or a GIR file.</p><p>If the library is written in Vala then valadoc can generate the documentation from the library&#39;s Vala source files.</p><ul class="section-toc"><li><a href="valadoc-guide/01-00-quick-start">1. Quick Start</a></li><li><a href="valadoc-guide/02-00-command-line-tool">2. Command Line Tool</a></li><li><a href="valadoc-guide/03-00-documentation-comment-markup">3. Documentation Comment Markup</a></li></ul>',5)])])}const f=e(n,[["render",l]]);export{p as __pageData,f as default};
